import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

import javax.servlet.http.Part;
import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.UUID;

@SpringBootApplication
@RestController
public class ProfilePictureUploader {

    public static void main(String[] args) {
        SpringApplication.run(ProfilePictureUploader.class, args);
    }

    @PostMapping("/upload")
    public ResponseEntity<String> uploadPicture(@RequestBody Part filePart) throws IOException {
        String originalFileName = filePart.getSubmittedFileName();
        UUID uuid = UUID.randomUUID();
        String newFileName = uuid + "." + getExtension(originalFileName);

        Path path = Paths.get("src/main/resources/static/pictures/" + newFileName);
        Files.copy(filePart.getInputStream(), path, StandardCopyOption.REPLACE_EXISTING);

        return ResponseEntity.status(HttpStatus.OK).body(getUrl(newFileName));
    }

    private String getExtension(String fileName) {
        int extensionIndex = fileName.lastIndexOf(".");
        if (extensionIndex > 0) {
            return fileName.substring(extensionIndex + 1);
        }
        return null;
    }

    private String getUrl(String newFileName) {
        return "/pictures/" + newFileName;
    }
}